mapper.select:
SELECT id, dp_flow_device, dp_flow_tag, dp_flow_location, dp_flow_equip, dp_flow_model, dp_flow_manu, dp_flow_range, dp_flow_meas_range, dp_flow_med_name, dp_flow_med_temp, dp_flow_med_press, dp_flow_connection, dp_flow_accuracy, dp_flow_heat, dp_flow_interlock, dp_flow_interlock_val, dp_flow_remark, dv_code, status, dv_type FROM dp_flow_meter
AND dp_flow_tag = #{queryParams.dpFlowTag}
AND dp_flow_heat = #{queryParams.dpFlowHeat}
AND dp_flow_interlock = #{queryParams.dpFlowInterlock}
AND dv_code LIKE CONCAT('%', #{queryParams.dvCode}, '%')
AND status = #{queryParams.status}
AND dv_type LIKE CONCAT('%', #{queryParams.dvType}, '%')
